const rows = $input.all().map(i => i.json);
const bySession = {};
for (const r of rows) {
  if (!bySession[r.session_id]) bySession[r.session_id] = [];
  bySession[r.session_id].push({ role: r.role, content: r.content, created_at: r.created_at });
}

const conversations = Object.entries(bySession).map(([sessionId, msgs]) => {
  const gotPaymentInfo = msgs.some(m => m.role === 'assistant' && m.content.includes('Alias: productoscapilarespg'));
  const sentReceipt = msgs.some(m => m.role === 'user' && m.content.includes('Imagen recibida'));
  return {
    sessionId,
    number: sessionId.split('@')[0],
    messageCount: msgs.length,
    firstMessageAt: msgs[0].created_at,
    lastMessageAt: msgs[msgs.length - 1].created_at,
    gotPaymentInfo,
    sentReceipt,
    transcript: msgs.map(m => (m.role === 'user' ? 'Cliente' : 'Dolores') + ': ' + m.content).join('\n')
  };
});

const totalConversations = conversations.length;
const gotPaymentInfoCount = conversations.filter(c => c.gotPaymentInfo).length;
const likelyConvertedCount = conversations.filter(c => c.gotPaymentInfo && c.sentReceipt).length;
const likelyLostCount = conversations.filter(c => c.gotPaymentInfo && !c.sentReceipt).length;

return [{
  json: {
    conversations,
    totalConversations,
    gotPaymentInfoCount,
    likelyConvertedCount,
    likelyLostCount
  }
}];

const d = $json;

if (d.totalConversations === 0) {
  return [{ json: { skip: true } }];
}

const transcripts = d.conversations.map((c, i) =>
  `--- Conversacion ${i + 1} (+${c.number}) ---\n` +
  `Mensajes: ${c.messageCount} | Recibio datos de pago: ${c.gotPaymentInfo ? 'SI' : 'NO'} | Mando comprobante despues: ${c.sentReceipt ? 'SI' : 'NO'}\n` +
  c.transcript
).join('\n\n');

const systemPrompt = `Sos un analista de ventas para PG Productos Capilares (venden el Combo Biotina por WhatsApp con una IA llamada Dolores que atiende).

Te paso las transcripciones completas de las conversaciones de la ultima semana entre la IA (Dolores) y clientes potenciales, junto con datos de cada una: si el cliente llego a recibir los datos de pago (Mercado Pago) y si despues mando un comprobante (senal de que probablemente compro).

Tu trabajo es analizar los casos donde el cliente recibio los datos de pago pero NUNCA mando comprobante (venta probablemente perdida), y tambien los casos donde la conversacion se corto antes de llegar a esa instancia, para identificar patrones y motivos probables por los que no se cerro la venta. Por ejemplo: objeciones de precio no resueltas, dudas sobre el producto sin responder bien, el cliente pidio pensarlo y no volvio, tiempos de envio, desconfianza, precio muy alto, competencia, etc.

Respondé en español rioplatense, en formato de reporte corto para mandar por WhatsApp al equipo (maximo 1500 caracteres). Usa bullets. Estructura:
1. Numeros generales (cuantas conversaciones, cuantas llegaron a pago, cuantas probablemente cerraron)
2. Los 3-4 motivos mas frecuentes por los que ves que no se cerraron ventas, con un ejemplo breve de cada uno
3. Una sugerencia concreta de mejora si la ves clara

No inventes datos que no esten en las transcripciones.`;

return [{
  json: {
    skip: false,
    systemPrompt,
    userMessage: `Datos de la semana:\n- Conversaciones totales: ${d.totalConversations}\n- Llegaron a recibir datos de pago: ${d.gotPaymentInfoCount}\n- Probablemente compraron (mandaron comprobante): ${d.likelyConvertedCount}\n- Recibieron datos de pago pero no mandaron comprobante (venta probablemente perdida): ${d.likelyLostCount}\n\nTranscripciones:\n\n${transcripts}`
  }
}];

